{
  "situations": [
    {
      "dialogue": "{{NAME}}, as folhas desta samambaia ficaram pálidas depois de dias longe da janela. Ela precisa obter energia para produzir matéria orgânica e manter suas funções.",
      "imagePrompt": "Uma samambaia em vaso num quarto pouco iluminado, folhas pálidas e inclinadas; uma janela fechada deixa entrar pouca luz. Ao lado, uma luminária apagada e um regador.",
      "options": [
        {
          "feedback": "Correto. A luz fornece energia para a fotossíntese; ela não é alimento nem matéria incorporada pela planta.",
          "isCorrect": true,
          "text": "Levá-la para mais luz"
        },
        {
          "feedback": "A água fornece matéria, mas não substitui a energia luminosa necessária para a produção de matéria orgânica.",
          "isCorrect": false,
          "text": "Regá-la mais"
        },
        {
          "feedback": "A planta não obtém sua energia comendo as próprias folhas; isso reduziria sua matéria disponível.",
          "isCorrect": false,
          "text": "Cortar folhas saudáveis"
        },
        {
          "feedback": "O solo fornece substâncias minerais, mas adicionar solo não resolve a falta de energia luminosa mostrada.",
          "isCorrect": false,
          "text": "Adicionar mais terra"
        }
      ],
      "question": "Qual ação atende primeiro à limitação mostrada?"
    },
    {
      "dialogue": "No aquário, um peixe come pequenos pedaços de ração. Essa matéria fornece material e energia para seus movimentos, crescimento e outras atividades do corpo.",
      "imagePrompt": "Peixe dourado em um aquário, aproximando-se de pequenos grânulos de ração na água. Há bolhas e pedras no fundo, sem plantas em destaque.",
      "options": [
        {
          "feedback": "Correto. O peixe obtém matéria e energia ao ingerir outros materiais orgânicos, portanto é consumidor.",
          "isCorrect": true,
          "text": "Consumidor"
        },
        {
          "feedback": "Produtores formam matéria orgânica usando uma fonte de energia, como plantas expostas à luz. O peixe depende da ração.",
          "isCorrect": false,
          "text": "Produtor"
        },
        {
          "feedback": "Decompositores atuam sobre restos e resíduos orgânicos. A evidência mostra o peixe ingerindo alimento.",
          "isCorrect": false,
          "text": "Decompositor"
        },
        {
          "feedback": "A luz pode iluminar o aquário, mas o peixe está obtendo matéria e energia da ração, não produzindo seu próprio alimento.",
          "isCorrect": false,
          "text": "Produtor pela luz"
        }
      ],
      "question": "Como esse peixe deve ser classificado quanto à obtenção de matéria e energia?"
    },
    {
      "dialogue": "Restos de folhas estão se desfazendo na composteira. Fungos visíveis no material usam esses restos e liberam substâncias mais simples no processo.",
      "imagePrompt": "Composteira doméstica aberta com folhas secas e cascas parcialmente decompostas, fios brancos de fungos visíveis e terra escura se formando.",
      "options": [
        {
          "feedback": "Correto. Os fungos usam restos orgânicos e participam de sua decomposição, liberando substâncias mais simples.",
          "isCorrect": true,
          "text": "Decompositores"
        },
        {
          "feedback": "Produtores fabricam matéria orgânica a partir de substâncias simples usando energia; os fungos da composteira usam restos já existentes.",
          "isCorrect": false,
          "text": "Produtores"
        },
        {
          "feedback": "Consumidores ingerem matéria orgânica, mas nesta situação o papel destacado é a decomposição dos restos.",
          "isCorrect": false,
          "text": "Consumidores"
        },
        {
          "feedback": "Os fungos não são resíduos: eles são seres vivos atuando sobre os resíduos da composteira.",
          "isCorrect": false,
          "text": "Resíduos orgânicos"
        }
      ],
      "question": "Qual é o papel dos fungos nessa composteira?"
    },
    {
      "dialogue": "Após uma corrida, uma pessoa respira mais rápido, sua temperatura aumenta e ela elimina suor. As células usaram matéria e energia para sustentar o esforço.",
      "imagePrompt": "Pessoa após correr em uma pista, respirando intensamente e suando, com gotas de suor no rosto e camiseta. Garrafa de água ao lado.",
      "options": [
        {
          "feedback": "Correto. O suor é eliminado pelo corpo durante o esforço, mostrando que o metabolismo também produz e elimina resíduos.",
          "isCorrect": true,
          "text": "Eliminar resíduos"
        },
        {
          "feedback": "Correr exige trabalho biológico, mas a observação específica do suor mostra a eliminação de uma substância pelo corpo.",
          "isCorrect": false,
          "text": "Produzir movimento"
        },
        {
          "feedback": "A pessoa já obteve energia antes e durante o esforço; o suor visível não é uma etapa de obtenção de energia.",
          "isCorrect": false,
          "text": "Obter energia"
        },
        {
          "feedback": "O suor não serve para incorporar matéria ao corpo; ele sai do organismo.",
          "isCorrect": false,
          "text": "Obter matéria"
        }
      ],
      "question": "Que aspecto do metabolismo é evidenciado diretamente pelo suor?"
    },
    {
      "dialogue": "Uma muda recebe água e sais minerais pelas raízes e gás carbônico do ar. Com luz, ela forma matéria orgânica que poderá ser usada no crescimento.",
      "imagePrompt": "Ilustração realista de uma muda verde em vaso: raízes no solo absorvendo água e sais minerais, setas do ar indicando gás carbônico entrando nas folhas e luz solar incidindo sobre elas.",
      "options": [
        {
          "feedback": "Correto. A água, os sais minerais e o gás carbônico fornecem matéria; a luz fornece energia para o processo.",
          "isCorrect": true,
          "text": "Água, sais e gás carbônico"
        },
        {
          "feedback": "A luz é essencial como fonte de energia, mas não é a matéria usada para formar a matéria orgânica da muda.",
          "isCorrect": false,
          "text": "Somente luz solar"
        },
        {
          "feedback": "O solo pode conter água e sais, mas a muda também precisa do gás carbônico indicado no ar.",
          "isCorrect": false,
          "text": "Somente terra do vaso"
        },
        {
          "feedback": "A muda não precisa comer folhas para obter matéria; ela usa as substâncias mostradas na situação.",
          "isCorrect": false,
          "text": "Folhas de outras plantas"
        }
      ],
      "question": "Quais elementos mostrados fornecem principalmente matéria para a muda?"
    }
  ]
}

